import React, { useEffect, useMemo, useState } from 'react'
import { environmentLogService, pondService, sensorService } from '../../services/api'
import DashboardCard, { evaluateMetric } from '../../components/DashboardCard'
import '../../styles/dashboard.css'
import '../../styles/dashboard-cards.css'
import '../../styles/technician/technician-layout.css'
import '../../styles/technician/technician-dashboard.css'

const toNumber = (value) => {
  const num = Number(value)
  return Number.isFinite(num) ? num : null
}

const formatTime = (value) => {
  if (!value) return '-'
  const date = new Date(value)
  if (Number.isNaN(date.getTime())) return '-'
  return new Intl.DateTimeFormat('vi-VN', {
    day: '2-digit',
    month: '2-digit',
    hour: '2-digit',
    minute: '2-digit',
    hour12: false,
    timeZone: 'Asia/Ho_Chi_Minh',
  }).format(date)
}

const normalizeType = (value) => String(value || '').trim().toLowerCase()

const sensorTypeToMetric = (value) => {
  const type = normalizeType(value)
  if (type === 'ph') return 'ph'
  if (type === 'temperature') return 'temperature'
  if (type === 'dissolved oxygen' || type === 'oxygen') return 'oxygen'
  if (type === 'salinity') return 'salinity'
  if (type === 'turbidity' || type === 'water level') return 'turbidity'
  return null
}

const metricMeta = {
  ph: { label: 'pH', unit: '' },
  temperature: { label: 'Temp', unit: '°C' },
  oxygen: { label: 'DO', unit: 'mg/L' },
  salinity: { label: 'Salinity', unit: 'ppt' },
  turbidity: { label: 'Turbidity', unit: 'NTU' },
}

export const TechnicianDashboard = () => {
  const [monitoredPonds, setMonitoredPonds] = useState([])
  const [recentEnvironmentLogs, setRecentEnvironmentLogs] = useState([])
  const [sensors, setSensors] = useState([])
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState('')

  useEffect(() => {
    const fetchData = async () => {
      try {
        setLoading(true)

        const [pondsRes, sensorsRes] = await Promise.all([
          pondService.getAllPonds(),
          sensorService.getAllSensors(),
        ])

        const ponds = pondsRes?.data?.data || []
        const allSensors = sensorsRes?.data?.data || []

        setMonitoredPonds(ponds)
        setSensors(allSensors)

        const pondLogResponses = await Promise.all(
          ponds.slice(0, 8).map((pond) => environmentLogService.getByPondId(pond.pond_id))
        )

        const pondMap = new Map(ponds.map((pond) => [String(pond.pond_id), pond]))
        const mergedLogs = pondLogResponses
          .flatMap((res) => res?.data?.data || [])
          .map((log) => {
            const pond = pondMap.get(String(log.pond_id))
            return {
              ...log,
              pond_code: pond?.pond_code || '-',
              pond_name: pond?.pond_name || '-',
            }
          })
          .sort((a, b) => {
            const timeA = new Date(a.recorded_at || a.created_at).getTime() || 0
            const timeB = new Date(b.recorded_at || b.created_at).getTime() || 0
            return timeB - timeA
          })

        setRecentEnvironmentLogs(mergedLogs.slice(0, 8))
        setError('')
      } catch (err) {
        setError(err?.response?.data?.message || 'Lỗi tải dữ liệu dashboard kỹ thuật viên')
      } finally {
        setLoading(false)
      }
    }

    fetchData()
  }, [])

  const activeSensors = useMemo(
    () => sensors.filter((sensor) => String(sensor.status || '').toUpperCase() === 'ACTIVE'),
    [sensors]
  )

  const monitoringStats = useMemo(
    () => ({
      totalPonds: monitoredPonds.length,
      activeSensors: activeSensors.length,
      recentLogs: recentEnvironmentLogs.length,
    }),
    [monitoredPonds, activeSensors, recentEnvironmentLogs]
  )

  const metricSummary = useMemo(() => {
    const base = {
      ph: null,
      temperature: null,
      oxygen: null,
      salinity: null,
      turbidity: null,
    }

    for (const sensor of activeSensors) {
      const metric = sensorTypeToMetric(sensor.sensor_type)
      if (!metric || base[metric] !== null) continue
      const value = toNumber(sensor.current_value)
      if (value !== null) base[metric] = value
    }

    return base
  }, [activeSensors])

  const sensorsByPond = useMemo(() => {
    const counts = new Map()
    for (const sensor of sensors) {
      const pondId = String(sensor.pond_id || '')
      if (!pondId) continue
      const current = counts.get(pondId) || 0
      counts.set(pondId, current + 1)
    }
    return counts
  }, [sensors])

  const alertItems = useMemo(() => {
    const items = []
    const offlineSensors = sensors.filter((sensor) => String(sensor.status || '').toUpperCase() !== 'ACTIVE')

    if (offlineSensors.length > 0) {
      items.push({ type: 'danger', text: `${offlineSensors.length} cảm biến đang ngoại tuyến` })
    }

    const turbidityAlert = recentEnvironmentLogs.find((log) => {
      const turbidity = toNumber(log.turbidity)
      return turbidity !== null && (turbidity < 0 || turbidity > 10)
    })

    if (turbidityAlert) {
      items.push({
        type: 'warning',
        text: `Độ đục bất thường tại ${turbidityAlert.pond_code || 'ao'} (${toNumber(turbidityAlert.turbidity)?.toFixed(1)} NTU)`,
      })
    }

    if (items.length === 0) {
      items.push({ type: 'info', text: 'Chưa phát hiện cảnh báo mới' })
    }

    return items
  }, [recentEnvironmentLogs, sensors])

  if (loading) {
    return (
      <div className="dashboard technician-page-shell technician-dashboard">
        <div className="flex-center page-loading">
          <div className="spinner"></div>
        </div>
      </div>
    )
  }

  return (
    <div className="dashboard technician-page-shell technician-dashboard">
      <div className="dashboard-header dashboard-header--split">
        <div>
          <h1>Dashboard</h1>
          <p>Tong quan hoat dong ao nuoi va cam bien</p>
        </div>
        <div className="dashboard-stats">
          <DashboardCard
            title="Tong so ao"
            value={monitoringStats.totalPonds}
            rating={evaluateMetric('ponds', monitoringStats.totalPonds)}
            description="Ao dang theo doi"
          />
          <DashboardCard
            title="Cam bien hoat dong"
            value={monitoringStats.activeSensors}
            rating={evaluateMetric('tasks', monitoringStats.activeSensors)}
            description="Dang online"
          />
        </div>
      </div>

      {error && <div className="alert alert-error">{error}</div>}

      <div className="tech-grid">
        <main className="tech-grid__main">
          <section className="pond-overview">
            <h2>Pond Monitoring Overview</h2>
            <div className="pond-cards">
              {monitoredPonds.slice(0, 6).map((pond) => {
                const pondLogs = recentEnvironmentLogs.filter((log) => String(log.pond_id) === String(pond.pond_id))
                const latest = pondLogs[0]
                return (
                  <article key={pond.pond_id} className="pond-card">
                    <header>
                      <strong>{pond.pond_code || `Ao ${pond.pond_id}`}</strong>
                      <span className="pond-status">{String(pond.status || 'BINH_THUONG')}</span>
                    </header>
                    <div className="pond-body">
                      <div className="pond-metric">DO<br /><small>{toNumber(latest?.oxygen)?.toFixed(1) || '-'} mg/L</small></div>
                      <div className="pond-metric">pH<br /><small>{toNumber(latest?.ph)?.toFixed(1) || '-'}</small></div>
                      <div className="pond-metric">Temp<br /><small>{toNumber(latest?.temperature)?.toFixed(1) || '-'} C</small></div>
                      <div className="pond-metric">Turb<br /><small>{toNumber(latest?.turbidity)?.toFixed(1) || '-'} NTU</small></div>
                    </div>
                    <footer>
                      <small>So cam bien: {sensorsByPond.get(String(pond.pond_id)) || 0}</small>
                    </footer>
                  </article>
                )
              })}
            </div>
          </section>

          <section className="recent-section">
            <h2>Recent Manual Environmental Inputs</h2>
            <div className="table-wrapper">
              <table>
                <thead>
                  <tr>
                    <th>Thoi gian</th>
                    <th>Nguoi nhap</th>
                    <th>Ao</th>
                    <th>pH</th>
                    <th>Nhiet do</th>
                    <th>DO</th>
                    <th>Do man</th>
                    <th>Do duc</th>
                  </tr>
                </thead>
                <tbody>
                  {recentEnvironmentLogs.length > 0 ? (
                    recentEnvironmentLogs.slice(0, 5).map((log) => (
                      <tr key={log.log_id || `${log.pond_id}-${log.created_at || log.recorded_at}`}>
                        <td>{formatTime(log.recorded_at || log.created_at)}</td>
                        <td>{log.created_by_name || log.created_by || '-'}</td>
                        <td>{log.pond_code || '-'}</td>
                        <td>{toNumber(log.ph)?.toFixed(1) || '-'}</td>
                        <td>{toNumber(log.temperature)?.toFixed(1) || '-'}</td>
                        <td>{toNumber(log.oxygen)?.toFixed(1) || '-'}</td>
                        <td>{toNumber(log.salinity)?.toFixed(1) || '-'}</td>
                        <td>{toNumber(log.turbidity)?.toFixed(1) || '-'}</td>
                      </tr>
                    ))
                  ) : (
                    <tr>
                      <td colSpan="8" className="table-empty-cell">Chua co ghi nhan moi truong thu cong</td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          </section>
        </main>

        <aside className="tech-grid__aside">
          <div className="realtime-summary">
            <h3>Real-time Sensor Summary</h3>
            <div className="realtime-cards">
              {Object.keys(metricMeta).map((metricKey) => {
                const value = metricSummary[metricKey]
                const meta = metricMeta[metricKey]
                return (
                  <div key={metricKey} className="realtime-card">
                    <div className="metric">{meta.label}</div>
                    <div className="value">
                      {value === null ? '-' : `${value.toFixed(1)}${meta.unit ? ` ${meta.unit}` : ''}`}
                    </div>
                  </div>
                )
              })}
            </div>
          </div>

          <div className="alerts-box">
            <h3>Alerts & Notifications</h3>
            <ul>
              {alertItems.map((item, index) => (
                <li key={`${item.type}-${index}`} className={`alert-item alert-${item.type}`}>
                  {item.text}
                </li>
              ))}
            </ul>
          </div>
        </aside>
      </div>
    </div>
  )
}

export default TechnicianDashboard
